import java.util.*;

public class Solution {
    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        boolean[] replaced = new boolean[n];
        long validCount = 0;

        // Function to calculate the number of valid substrings
        long countValidSubstrings() {
            validCount = 0;
            List<Integer> starPositions = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                if (replaced[i]) {
                    starPositions.add(i);
                }
            }
            for (int idx : starPositions) {
                int left = idx;
                int right = idx;
                while (left >= 0 && right < n) {
                    if (s.charAt(left) == '*' || s.charAt(right) == '*') {
                        validCount += 1;
                    }
                    left--;
                    right++;
                }
            }
            return validCount;
        }

        for (int t = 0; t < n; t++) {
            int pos = (int) order[t];
            if (!replaced[pos]) {
                replaced[pos] = true;
                long currentCount = countValidSubstrings();
                if (currentCount >= k) {
                    return t;
                }
            }
        }
        return -1;
    }
}
